}

public Map<String, Object> getNoticeDetail(Long noticeId) {
    Map<String, Object> result = new HashMap<>();
    NoticeDto dto = noticeDao.selectDetail(noticeId);

    result.put("title", dto.getTitle());
    result.put("body", dto.getBody());
    return result;
}

public Map<String, Object> detail(Long noticeId) {
    Map<String, Object> response = new HashMap<>();
    response.put("status", "ok");
    response.put("data", noticeService.getNoticeDetail(noticeId));
    return response;
}

public class NoticeDto {
    private String title;
    private String body;
}

function openTechFiles(row) {
  if (!row || row.has_tech_file !== 'Y') {
    return;
  }

  popup.open({ grp_cd: row.grp_cd });
}

function bindTechColumn(grid) {
  grid.on('tech-click', function(row) {
    openTechFiles(row);
  });
}

@RequestMapping("/contents/tech/selectTechFileList.do")
public ResultMap selectTechFileList(@RequestBody Map<String, Object> param) {
