}

function open(params) {
  this.params = params;
  if (params.grp_cd_list && params.grp_cd_list.length) {
    this.onSearchAll(params.grp_cd_list);
    return;
  }
  if (params.grp_cd) {
    this.onSearch(params.grp_cd);
  }
}

public void downloadAgencyStamp(String agencyCd, HttpServletResponse response) throws Exception {
    Map<String, Object> fileInfo = agencyService.selectAgencyStampFileInfo(agencyCd);
    if (fileInfo == null) {
        return;
    }

    String root = propertiesService.getString("webroot.dir");
    File target = new File(root + "/" + fileInfo.get("ATT_FILE_PATH") + "/" + fileInfo.get("ATT_FILE_NM"));
    FileCopyUtils.copy(new FileInputStream(target), response.getOutputStream());
}

public Map<String, Object> selectAgencyStampFileInfo(String agencyCd) throws Exception {
    return agencyDao.selectAgencyStampFileInfo(agencyCd);
}

